import React, { useState } from 'react';
import { motion } from 'framer-motion';

export default function RSVPForm({ onSubmissionSuccess }) {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    guests: 1,
    attending: 'yes',
    message: ''
  });

  const handleSubmit = (e) => {
    e.preventDefault();
    // Logic for backend post goes here
    console.log("RSVP Data:", formData);
    onSubmissionSuccess(formData);
  };

  return (
    <motion.div 
      initial={{ opacity: 0, scale: 0.95 }}
      whileInView={{ opacity: 1, scale: 1 }}
      className="max-w-xl mx-auto p-10 bg-white shadow-2xl border-t-4 border-luxury-gold"
    >
      <h3 className="font-serif text-3xl text-luxury-dark text-center mb-8 italic">Kindly Respond</h3>
      <form onSubmit={handleSubmit} className="space-y-6">
        <div>
          <label className="block text-xs uppercase tracking-widest text-luxury-accent mb-2">Your Full Name</label>
          <input 
            type="text" 
            required
            className="w-full border-b border-gray-200 py-2 focus:border-luxury-gold outline-none transition-colors"
            onChange={(e) => setFormData({...formData, name: e.target.value})}
          />
        </div>
        
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-xs uppercase tracking-widest text-luxury-accent mb-2">Number of Guests</label>
            <select 
              className="w-full border-b border-gray-200 py-2 bg-transparent outline-none"
              onChange={(e) => setFormData({...formData, guests: e.target.value})}
            >
              {[1,2,3,4].map(num => <option key={num} value={num}>{num}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-xs uppercase tracking-widest text-luxury-accent mb-2">Attending?</label>
            <select 
              className="w-full border-b border-gray-200 py-2 bg-transparent outline-none"
              onChange={(e) => setFormData({...formData, attending: e.target.value})}
            >
              <option value="yes">Joyfully Accept</option>
              <option value="no">Regretfully Decline</option>
            </select>
          </div>
        </div>

        <button 
          type="submit" 
          className="w-full bg-luxury-dark text-white py-4 tracking-[0.2em] uppercase text-xs hover:bg-luxury-gold transition-all duration-500"
        >
          Submit RSVP
        </button>
      </form>
    </motion.div>
  );
}
